func formatSignalData(signal *app.QueueSignal) string {
	data, err := json.MarshalIndent(signal.Signal, "", "  ")
	if err != nil {
		return "{}"
	}
	return string(data)
}

func hasTimingMetadata(signal *app.QueueSignal) bool {
	return true
}

func getMetadataString(status app.CompositeStatus, key string) string {
	if v, ok := status.Metadata[key]; ok {
		return fmt.Sprintf("%v", v)
	}
	for _, h := range status.History {
		if v, ok := h.Metadata[key]; ok {
			return fmt.Sprintf("%v", v)
		}
	}
	return ""
}

func formatDuration(d time.Duration) string {
	if d < 0 {
		return "0s"
	}
	if d < time.Second {
		return fmt.Sprintf("%dms", d.Milliseconds())
	}
	if d < time.Minute {
		return fmt.Sprintf("%.1fs", d.Seconds())
	}
	return fmt.Sprintf("%dm %ds", int(d.Minutes()), int(d.Seconds())%60)
}

func computeDuration(signal *app.QueueSignal) string {
	startStr := getMetadataString(signal.Status, "execute_started_at")
	endStr := getMetadataString(signal.Status, "execute_finished_at")
	if startStr == "" || endStr == "" {
		return ""
	}
	start, err := time.Parse(time.RFC3339, startStr)
	if err != nil {
		return ""
	}
	end, err := time.Parse(time.RFC3339, endStr)
	if err != nil {
		return ""
	}
	return formatDuration(end.Sub(start))
}

func computeDequeuedToExecute(signal *app.QueueSignal) string {
	dequeuedStr := getMetadataString(signal.Status, "dequeued_at")
	startStr := getMetadataString(signal.Status, "execute_started_at")
	if dequeuedStr == "" || startStr == "" {
		return ""
	}
	dequeued, err := time.Parse(time.RFC3339, dequeuedStr)
	if err != nil {
		return ""
	}
	start, err := time.Parse(time.RFC3339, startStr)
	if err != nil {
		return ""
	}
	return formatDuration(start.Sub(dequeued))
}

func computeQueueWait(signal *app.QueueSignal) string {
	dequeuedStr := getMetadataString(signal.Status, "dequeued_at")
	if dequeuedStr == "" {
		return ""
	}
	dequeued, err := time.Parse(time.RFC3339, dequeuedStr)
	if err != nil {
		return ""
	}
	return formatDuration(dequeued.Sub(signal.CreatedAt))
}

